function solve(points) {
    const n = points.length;
    const slopeMap = new Map();

    // Function to calculate the slope between two points
    function getSlope(p1, p2) {
        const dx = p2[0] - p1[0];
        const dy = p2[1] - p1[1];
        if (dx === 0 && dy === 0) return null; // same point
        if (dx === 0) return Infinity; // vertical line
        return dy / dx;
    }

    // Count the number of pairs of points with the same slope
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const slope = getSlope(points[i], points[j]);
            if (slope !== null) {
                const key = `${slope}`;
                if (!slopeMap.has(key)) {
                    slopeMap.set(key, 0);
                }
                slopeMap.set(key, slopeMap.get(key) + 1);
            }
        }
    }

    // Calculate the number of trapezoids
    let count = 0;
    for (const [slope, cnt] of slopeMap.entries()) {
        if (cnt >= 2) {
            // Number of ways to choose 2 pairs of points with the same slope
            const ways = cnt * (cnt - 1) / 2;
            count += ways;
        }
    }

    return count;
}

